## 2️⃣  `pcapng_stubs.cpp` – C/C++ glue code

```cpp
/*--------------------------------------------------------------------
   pcapng_stubs.cpp – C++ implementation of the OCaml binding
  --------------------------------------------------------------------*/

#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/callback.h>
#include <caml/fail.h>
#include <caml/bigarray.h>

#include <string>
#include <exception>
#include <cstring>

/* ------------------------------------------------------------------
   The (fictional) libpcapng API we are binding to.
   Replace the following includes / declarations with the real library
   headers if they differ.
   ------------------------------------------------------------------ */
#include "libpcapng.hpp"   // <-- your real header

/* ------------------------------------------------------------------
   Helper macros to turn a custom OCaml block into a C++ pointer.
   ------------------------------------------------------------------ */
#define PcapNG_val(v) (*((PcapNG **) Data_custom_val(v)))

/* ------------------------------------------------------------------
   Custom operations for the abstract handle.
   ------------------------------------------------------------------ */
static void pcapng_finalize(value v) {
  PcapNG *ptr = PcapNG_val(v);
  if (ptr != nullptr) {
    delete ptr;
    PcapNG_val(v) = nullptr;
  }
}
static int pcapng_compare(value v1, value v2) {
  PcapNG *p1 = PcapNG_val(v1);
  PcapNG *p2 = PcapNG_val(v2);
  return p1 < p2 ? -1 : (p1 > p2);
}
static intnat pcapng_hash(value v) {
  return (intnat)PcapNG_val(v);
}
static struct custom_operations pcapng_ops = {
  "pcapng_handle",
  pcapng_finalize,
  pcapng_compare,
  pcapng_hash,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default
};

/* ------------------------------------------------------------------
   OCaml <-> C++ conversion helpers
   ------------------------------------------------------------------ */

/* Convert a C++ Frame into an OCaml [frame] record.
   The order of fields must match the order in the .mli record definition.
*/
static value caml_of_frame(const Frame &fr) {
  CAMLparam0();
  CAMLlocal1(ocaml_fr);

  /* Allocate a block with 5 fields (tag 0 = normal record). */
  ocaml_fr = caml_alloc(5, 0);

  Store_field(ocaml_fr, 0, Val_int(fr.ts_sec));
  Store_field(ocaml_fr, 1, Val_int(fr.ts_usec));
  Store_field(ocaml_fr, 2, Val_int(fr.captured_len));
  Store_field(ocaml_fr, 3, Val_int(fr.original_len));

  /* Copy the raw packet bytes into an OCaml bytes value. */
  value data_val = caml_alloc_string(fr.captured_len);
  memcpy(String_val(data_val), fr.data, fr.captured_len);
  Store_field(ocaml_fr, 4, data_val);

  CAMLreturn(ocaml_fr);
}

/* ------------------------------------------------------------------
   OCaml primitives
   ------------------------------------------------------------------ */

/* val open_file : string -> t */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
  CAMLparam1(v_path);
  CAMLlocal1(v_handle);

  const char *c_path = String_val(v_path);
  try {
    PcapNG *ptr = new PcapNG(std::string(c_path));
    v_handle = caml_alloc_custom(&pcapng_ops, sizeof(PcapNG *), 0, 1);
    PcapNG_val(v_handle) = ptr;
    CAMLreturn(v_handle);
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  } catch (...) {
    caml_failwith("pcapng: unknown error while opening file");
  }
}

/* val close : t -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
  CAMLparam1(v_handle);
  /* The finalizer already does the delete, but we also allow an
     explicit close that clears the pointer early. */
  PcapNG *ptr = PcapNG_val(v_handle);
  if (ptr != nullptr) {
    delete ptr;
    PcapNG_val(v_handle) = nullptr;
  }
  CAMLreturn(Val_unit);
}

/* val iter_frames : t -> (frame -> unit) -> unit */
extern "C" CAMLprim value caml_pcapng_iter_frames(value v_handle,
                                                value v_cb) {
  CAMLparam2(v_handle, v_cb);
  CAMLlocal1(v_frame);

  PcapNG *ptr = PcapNG_val(v_handle);
  if (ptr == nullptr) caml_failwith("pcapng: handle is closed");

  try {
    for (auto it = ptr->begin(); it != ptr->end(); ++it) {
      const Frame &fr = *it;
      v_frame = caml_of_frame(fr);

      /* Call the OCaml callback.  Use caml_callback_exn so we can
         propagate exceptions correctly. */
      value res = caml_callback_exn(v_cb, v_frame);
      if (Is_exception_result(res)) {
        /* Propagate the OCaml exception back to the caller. */
        caml_raise(res);
      }
      /* No need to keep the frame value around – it will be reclaimed
         by the GC on the next allocation. */
    }
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  } catch (...) {
    caml_failwith("pcapng: unknown error during iteration");
  }

  CAMLreturn(Val_unit);
}

/* val with_file : string -> (t -> 'a) -> 'a */
extern "C" CAMLprim value caml_pcapng_with_file(value v_path,
                                               value v_fun) {
  CAMLparam2(v_path, v_fun);
  CAMLlocal1(v_handle);
  CAMLlocal1(v_res);

  /* Open the file – any failure raises an exception and aborts. */
  v_handle = caml_pcapng_open_file(v_path);

  /* Ensure the file is closed even if the user function raises. */
  caml_enter_blocking_section();   /* allow other threads while we run user code */
  v_res = caml_callback(v_fun, v_handle);
  caml_leave_blocking_section();

  caml_pcapng_close(v_handle);
  CAMLreturn(v_res);
}

/* ------------------------------------------------------------------
   Register the primitives for the OCaml linker.
   ------------------------------------------------------------------ */
static struct caml_named_value {
  const char *name;
  value (*fn)();
} caml_primitives[] = {
  {"pcapng_open_file",   caml_pcapng_open_file},
  {"pcapng_close",       caml_pcapng_close},
  {"pcapng_iter_frames", caml_pcapng_iter_frames},
  {"pcapng_with_file",   caml_pcapng_with_file},
  {nullptr, nullptr}
};

extern "C" void caml_register_prims(void) {
  for (int i = 0; caml_primitives[i].name != nullptr; ++i) {
    caml_register_named_value(caml_primitives[i].name,
                              caml_primitives[i].fn);
  }
}
```

### How to compile

```sh
# Assuming the C++ library header is libpcapng.hpp and the lib is -lpcapng
ocamlopt -c pcapng.mli               # produces pcapng.cmi
ocamlopt -c pcapng.ml                 # (empty file, just for completeness)

# Compile the stub as C++ and produce a shared object
g++ -I$(ocamlopt -where) -I. -fPIC -c pcapng_stubs.cpp -o pcapng_stubs.o
g++ -shared -o libpcapng_stubs.so pcapng_stubs.o -lpcapng

# Link everything together
ocamlopt -o test_program pcapng.cmx libpcapng_stubs.so test_program.ml
```

> **Note** – the stub is compiled with a C++ compiler (`g++`) because it
> directly uses the C++ API.  The `extern "C"` wrappers guarantee the
> symbols have the right (C) linkage for the OCaml runtime.

